/**
 * MemoryTree heartbeat — single execution, stateless, idempotent.
 * Port of scripts/heartbeat.py
 */

import type { ParsedTranscript } from '../types/transcript.js'
import { discoverSourceFiles, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot } from '../transcript/discover.js'
import type { Config } from './config.js'
import { loadConfig } from './config.js'
import { acquireLock, releaseLock } from './lock.js'
import { resetFailureCount, writeAlert, writeAlertWithThreshold } from './alert.js'
import type { LogLevel } from './log.js'
import { getLogger, setupLogging } from './log.js'
import { git } from '../utils/exec.js'
import { toPosixPath } from '../utils/path.js'
import { basename, join, resolve } from 'node:path'
import { existsSync } from 'node:fs'

// ---------------------------------------------------------------------------
// Sensitive pattern detection
// ---------------------------------------------------------------------------

const SENSITIVE_PATTERNS: readonly RegExp[] = [
  /(?:api[_-]?key|apikey)\s*[:=]\s*\S+/i,
  /(?:password|passwd|pwd)\s*[:=]\s*\S+/i,
  /(?:secret|token)\s*[:=]\s*\S+/i,
  /(?:sk-|pk_live_|sk_live_|ghp_|gho_|glpat-)\S{10,}/,
  /Bearer\s+\S{20,}/i,
]

const RAW_TRANSCRIPT_PREFIX = 'Memory/06_transcripts/raw/'

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export async function main(): Promise<number> {
  const config = loadConfig()
  setupLogging(config.log_level as LogLevel)
  const logger = getLogger()

  if (!acquireLock()) {
    logger.info('Another heartbeat instance is running. Exiting.')
    writeAlert('global', 'lock_held', 'Heartbeat exited: another instance held the lock.')
    return 0
  }

  try {
    return await runHeartbeat(config)
  } finally {
    releaseLock()
  }
}

// ---------------------------------------------------------------------------
// Heartbeat orchestration
// ---------------------------------------------------------------------------

export async function runHeartbeat(config: Config): Promise<number> {
  const logger = getLogger()

  if (config.projects.length === 0) {
    logger.info('No projects registered in config.toml. Nothing to do.')
    return 0
  }

  logger.info(`Heartbeat started. ${config.projects.length} project(s) registered.`)

  for (const entry of config.projects) {
    const projectPath = resolve(entry.path)
    if (!existsSync(projectPath)) {
      logger.warn(`Project path does not exist, skipping: ${projectPath}`)
      continue
    }
    try {
      await processProject(config, projectPath, entry.name || basename(projectPath))
    } catch (err: unknown) {
      logger.exception(`Error processing project: ${projectPath}`, err)
      writeAlertWithThreshold(
        toPosixPath(projectPath),
        'push_failed',
        `Heartbeat error for project: ${basename(projectPath)}`,
      )
    }
  }

  logger.info('Heartbeat finished.')
  return 0
}

// ---------------------------------------------------------------------------
// Per-project processing
// ---------------------------------------------------------------------------

export async function processProject(config: Config, projectPath: string, projectName: string): Promise<void> {
  const logger = getLogger()
  const repoSlug = slugify(projectName, 'project')
  const globalRoot = defaultGlobalTranscriptRoot()
  const branch = currentBranch(projectPath)
  const mirrorToRepo = isDedicatedMemorytreeBranch(branch)

  if (!mirrorToRepo) {
    logger.warn(
      `[${projectName}] Current branch '${branch}' is not a dedicated memorytree/* branch. ` +
      'Importing to the global archive only.',
    )
  }

  const discovered = discoverSourceFiles()
  let importedCount = 0

  for (const [client, source] of discovered) {
    let parsed: ParsedTranscript
    try {
      parsed = parseTranscript(client, source)
    } catch {
      logger.debug(`Failed to parse ${source}, skipping.`)
      continue
    }

    if (!transcriptHasContent(parsed)) continue
    if (!transcriptMatchesRepo(parsed, projectPath, repoSlug)) continue

    scanSensitive(parsed, projectPath)

    try {
      await importTranscript(parsed, projectPath, globalRoot, repoSlug, 'not-set', mirrorToRepo)
      importedCount++
    } catch {
      logger.exception(`Failed to import transcript: ${source}`)
    }
  }

  if (importedCount === 0) {
    logger.info(`[${projectName}] No new transcripts to import.`)
    return
  }

  logger.info(`[${projectName}] Imported ${importedCount} transcript(s).`)
  if (mirrorToRepo) {
    gitCommitAndPush(config, projectPath, projectName, importedCount)
  } else {
    logger.info(`[${projectName}] Skipped repo-local commit/push on branch '${branch}'.`)
  }

  if (config.generate_report) {
    try {
      const { buildReport } = await import('../report/build.js')
      await buildReport({
        root: projectPath,
        output: join(projectPath, 'Memory', '07_reports'),
        noAi: !process.env['ANTHROPIC_API_KEY'],
        model: config.ai_summary_model,
        locale: config.locale,
        ghPagesBranch: config.gh_pages_branch,
        cname: config.cname,
        webhookUrl: config.webhook_url,
        reportBaseUrl: config.report_base_url,
      })
      logger.info(`[${projectName}] Report generated.`)
    } catch (err: unknown) {
      logger.warn(`[${projectName}] Report generation failed: ${String(err)}`)
      // Never propagate — report failure must not abort heartbeat cycle
    }
  }
}

// ---------------------------------------------------------------------------
// Sensitive pattern scanning
// ---------------------------------------------------------------------------

export function scanSensitive(parsed: ParsedTranscript, projectPath: string): void {
  const logger = getLogger()
  for (const msg of parsed.messages) {
    for (const pattern of SENSITIVE_PATTERNS) {
      if (pattern.test(msg.text)) {
        logger.warn(
          `Sensitive pattern detected in transcript ${parsed.source_path} (project: ${basename(projectPath)}, role: ${msg.role})`,
        )
        writeAlert(
          toPosixPath(projectPath),
          'sensitive_match',
          `Sensitive pattern in transcript: ${basename(parsed.source_path)}`,
        )
        return
      }
    }
  }
}

// ---------------------------------------------------------------------------
// Git operations
// ---------------------------------------------------------------------------

export function gitCommitAndPush(config: Config, projectPath: string, projectName: string, count: number): void {
  const logger = getLogger()

  const changedPaths = changedMemoryPaths(projectPath)
  if (changedPaths.length === 0) {
    logger.info(`[${projectName}] No git changes in Memory/.`)
    return
  }

  const stageablePaths = changedPaths.filter(path => !isRepoRawTranscriptPath(path))
  if (stageablePaths.length === 0) {
    logger.info(`[${projectName}] Only raw transcript mirror changes detected; skipping commit.`)
    return
  }

  git(projectPath, 'add', '--', ...stageablePaths)
  git(projectPath, 'commit', '-m', `memorytree(transcripts): import ${count} transcript(s)`)
  logger.info(`[${projectName}] Committed ${count} transcript import(s).`)

  if (!config.auto_push) {
    logger.info(`[${projectName}] auto_push disabled, skipping push.`)
    return
  }

  const remotes = git(projectPath, 'remote')
  if (!remotes.trim()) {
    logger.warn(`[${projectName}] No git remote configured, skipping push.`)
    writeAlert(toPosixPath(projectPath), 'no_remote', 'Push skipped: no Git remote configured.')
    return
  }

  if (!tryPush(projectPath, projectName)) {
    logger.warn(`[${projectName}] Push failed, retrying once...`)
    if (!tryPush(projectPath, projectName)) {
      logger.error(`[${projectName}] Push failed after retry.`)
      writeAlertWithThreshold(toPosixPath(projectPath), 'push_failed', 'Push failed after retry.')
      return
    }
  }

  resetFailureCount(toPosixPath(projectPath), 'push_failed')
}

export function tryPush(projectPath: string, projectName: string): boolean {
  try {
    git(projectPath, 'push')
    getLogger().info(`[${projectName}] Pushed successfully.`)
    return true
  } catch {
    return false
  }
}

export function currentBranch(projectPath: string): string {
  return git(projectPath, 'rev-parse', '--abbrev-ref', 'HEAD').trim()
}

export function isDedicatedMemorytreeBranch(branch: string): boolean {
  return branch.trim().startsWith('memorytree/')
}

export function changedMemoryPaths(projectPath: string): string[] {
  const status = git(projectPath, 'status', '--porcelain', '--untracked-files=all', '--', 'Memory/')
  const seen = new Set<string>()
  const paths: string[] = []

  for (const rawLine of status.split(/\r?\n/)) {
    const path = statusLinePath(rawLine)
    if (path === null || seen.has(path)) continue
    seen.add(path)
    paths.push(path)
  }

  return paths
}

export function isRepoRawTranscriptPath(path: string): boolean {
  return path.replace(/\\/g, '/').startsWith(RAW_TRANSCRIPT_PREFIX)
}

function statusLinePath(line: string): string | null {
  if (line.length < 4) return null

  const rawPath = line.slice(3).trim()
  if (!rawPath) return null

  const path = rawPath.includes(' -> ')
    ? rawPath.slice(rawPath.lastIndexOf(' -> ') + 4)
    : rawPath

  return unquotePath(path)
}

function unquotePath(path: string): string {
  if (!(path.startsWith('"') && path.endsWith('"'))) return path

  return path
    .slice(1, -1)
    .replace(/\\"/g, '"')
    .replace(/\\\\/g, '\\')
}

/**
 * CLI: memorytree daemon install|uninstall|run-once|watch|status
 * Port of scripts/memorytree_daemon.py
 */

import { existsSync, mkdirSync, writeFileSync, unlinkSync } from 'node:fs'
import { homedir } from 'node:os'
import { resolve, dirname } from 'node:path'
import { platform } from 'node:process'

import { configPath, intervalToSeconds, loadConfig, saveConfig } from '../heartbeat/config.js'
import { readLockPid } from '../heartbeat/lock.js'
import { execCommand } from '../utils/exec.js'

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const TASK_NAME = 'MemoryTree Heartbeat'
const LAUNCHD_LABEL = 'com.memorytree.heartbeat'

// ---------------------------------------------------------------------------
// Subcommands
// ---------------------------------------------------------------------------

export function cmdInstall(options: { interval?: string; autoPush?: string }): number {
  let config = loadConfig()

  if (options.interval) {
    config = { ...config, heartbeat_interval: options.interval }
  }
  if (options.autoPush) {
    config = { ...config, auto_push: options.autoPush === 'true' }
  }

  saveConfig(config)
  const seconds = intervalToSeconds(config.heartbeat_interval)
  const scriptPath = heartbeatScriptPath()

  const sys = platform
  if (sys === 'linux') return installCron(scriptPath, seconds)
  if (sys === 'darwin') return installLaunchd(scriptPath, seconds)
  if (sys === 'win32') return installSchtasks(scriptPath, seconds)

  process.stderr.write(`Unsupported platform: ${sys}\n`)
  return 1
}

export function cmdUninstall(): number {
  const sys = platform
  if (sys === 'linux') return uninstallCron()
  if (sys === 'darwin') return uninstallLaunchd()
  if (sys === 'win32') return uninstallSchtasks()

  process.stderr.write(`Unsupported platform: ${sys}\n`)
  return 1
}

export async function cmdRunOnce(): Promise<number> {
  const { main } = await import('../heartbeat/heartbeat.js')
  return main()
}

export async function cmdWatch(options: { interval?: string }): Promise<number> {
  const config = loadConfig()
  const intervalStr = options.interval ?? config.heartbeat_interval
  const seconds = intervalToSeconds(intervalStr)
  const { main } = await import('../heartbeat/heartbeat.js')

  process.stdout.write(`Watch mode: running heartbeat every ${seconds}s. Press Ctrl+C to stop.\n`)
  try {
    // eslint-disable-next-line no-constant-condition
    while (true) {
      await main()
      await new Promise(r => setTimeout(r, seconds * 1000))
    }
  } catch {
    process.stdout.write('\nWatch mode stopped.\n')
  }
  return 0
}

export function cmdStatus(): number {
  const sys = platform

  let registered = false
  if (sys === 'linux') registered = isCronRegistered()
  else if (sys === 'darwin') registered = isLaunchdRegistered()
  else if (sys === 'win32') registered = isSchtasksRegistered()

  const platformName = sys === 'darwin' ? 'Darwin' : sys === 'win32' ? 'Windows' : 'Linux'
  process.stdout.write(`Platform:   ${platformName}\n`)
  process.stdout.write(`Registered: ${registered ? 'yes' : 'no'}\n`)

  const pid = readLockPid()
  if (pid !== null) {
    process.stdout.write(`Lock:       held by PID ${pid}\n`)
  } else {
    process.stdout.write('Lock:       not held\n')
  }

  if (existsSync(configPath())) {
    const config = loadConfig()
    process.stdout.write(`Interval:   ${config.heartbeat_interval}\n`)
    process.stdout.write(`Auto-push:  ${config.auto_push}\n`)
    process.stdout.write(`Projects:   ${config.projects.length}\n`)
  } else {
    process.stdout.write('Config:     not found (using defaults)\n')
  }

  return 0
}

// ---------------------------------------------------------------------------
// Linux (cron)
// ---------------------------------------------------------------------------

function installCron(scriptPath: string, seconds: number): number {
  if (isCronRegistered()) {
    process.stderr.write("Heartbeat is already registered in cron. Use 'uninstall' first.\n")
    return 1
  }

  const minutes = Math.max(1, Math.floor(seconds / 60))
  const logDir = resolve(homedir(), '.memorytree', 'logs')
  mkdirSync(logDir, { recursive: true })

  const cronLine = `*/${minutes} * * * * node "${scriptPath}" daemon run-once >> "${resolve(logDir, 'heartbeat-cron.log')}" 2>&1 # memorytree`
  const existing = getCrontab()
  const newCrontab = existing.trim()
    ? existing.trimEnd() + '\n' + cronLine + '\n'
    : cronLine + '\n'

  try {
    const tmpFile = resolve(homedir(), '.memorytree', '.crontab.tmp')
    writeFileSync(tmpFile, newCrontab)
    execCommand('crontab', [tmpFile])
    unlinkSync(tmpFile)
  } catch {
    process.stderr.write('Failed to install cron job.\n')
    return 1
  }

  process.stdout.write(`Heartbeat registered in cron (every ${minutes}m).\n`)
  return 0
}

function uninstallCron(): number {
  const existing = getCrontab()
  const filtered = existing.split('\n').filter(line => !line.includes('memorytree')).join('\n') + '\n'
  try {
    const tmpFile = resolve(homedir(), '.memorytree', '.crontab.tmp')
    mkdirSync(dirname(tmpFile), { recursive: true })
    writeFileSync(tmpFile, filtered)
    execCommand('crontab', [tmpFile])
    unlinkSync(tmpFile)
  } catch {
    // best effort
  }
  process.stdout.write('Heartbeat removed from cron.\n')
  return 0
}

export function isCronRegistered(): boolean {
  return getCrontab().includes('memorytree')
}

function getCrontab(): string {
  try {
    return execCommand('crontab', ['-l'], { allowFailure: true })
  } catch {
    return ''
  }
}

// ---------------------------------------------------------------------------
// macOS (launchd)
// ---------------------------------------------------------------------------

function launchdPlistPath(): string {
  return resolve(homedir(), 'Library', 'LaunchAgents', `${LAUNCHD_LABEL}.plist`)
}

function installLaunchd(scriptPath: string, seconds: number): number {
  const plistPath = launchdPlistPath()
  if (existsSync(plistPath)) {
    process.stderr.write("Heartbeat plist already exists. Use 'uninstall' first.\n")
    return 1
  }

  const logDir = resolve(homedir(), '.memorytree', 'logs')
  mkdirSync(logDir, { recursive: true })

  const plistContent = `<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>Label</key>
    <string>${LAUNCHD_LABEL}</string>
    <key>ProgramArguments</key>
    <array>
        <string>node</string>
        <string>${scriptPath}</string>
        <string>daemon</string>
        <string>run-once</string>
    </array>
    <key>StartInterval</key>
    <integer>${seconds}</integer>
    <key>StandardOutPath</key>
    <string>${resolve(logDir, 'heartbeat-launchd.log')}</string>
    <key>StandardErrorPath</key>
    <string>${resolve(logDir, 'heartbeat-launchd.log')}</string>
</dict>
</plist>
`
  mkdirSync(dirname(plistPath), { recursive: true })
  writeFileSync(plistPath, plistContent, 'utf-8')

  try {
    execCommand('launchctl', ['load', plistPath])
  } catch {
    process.stderr.write('Failed to load plist.\n')
    return 1
  }

  process.stdout.write(`Heartbeat registered via launchd (every ${seconds}s).\n`)
  return 0
}

function uninstallLaunchd(): number {
  const plistPath = launchdPlistPath()
  if (existsSync(plistPath)) {
    try { execCommand('launchctl', ['unload', plistPath], { allowFailure: true }) } catch { /* ignore */ }
    try { unlinkSync(plistPath) } catch { /* ignore */ }
  }
  process.stdout.write('Heartbeat removed from launchd.\n')
  return 0
}

export function isLaunchdRegistered(): boolean {
  return existsSync(launchdPlistPath())
}

// ---------------------------------------------------------------------------
// Windows (Task Scheduler)
// ---------------------------------------------------------------------------

// Write a VBScript launcher that runs node silently (no console window).
// wscript.exe /B runs in batch mode (suppresses script error popups).
// VBScript Run(..., 0, False): 0 = SW_HIDE hides the window; False = fire-and-forget.
// Written as UTF-16 LE with BOM so wscript.exe handles non-ASCII paths (e.g. Chinese
// usernames) correctly on all Windows versions.
export function vbsLauncherPath(): string {
  return resolve(homedir(), '.memorytree', 'heartbeat-launcher.vbs')
}

export function writeVbsLauncher(scriptPath: string): string {
  const vbsPath = vbsLauncherPath()
  mkdirSync(dirname(vbsPath), { recursive: true })
  // Inside VBScript strings, double-quote is escaped as ""
  const escapedScript = scriptPath.replace(/"/g, '""')
  // Use the full node binary path so the launcher works even when Task Scheduler's
  // PATH differs from the user's shell (e.g. nvm/fnm environments).
  const escapedNode = process.execPath.replace(/"/g, '""')
  const content = [
    'Set WshShell = CreateObject("WScript.Shell")',
    `WshShell.Run """${escapedNode}"" ""${escapedScript}"" daemon run-once", 0, False`,
  ].join('\r\n') + '\r\n'
  // UTF-16 LE BOM: recognised by wscript.exe on all Windows versions and preserves
  // non-ASCII characters (e.g. Chinese home directory paths) without corruption.
  const buf = Buffer.concat([Buffer.from([0xff, 0xfe]), Buffer.from(content, 'utf16le')])
  writeFileSync(vbsPath, buf)
  return vbsPath
}

function installSchtasks(scriptPath: string, seconds: number): number {
  if (isSchtasksRegistered()) {
    process.stderr.write("Heartbeat is already registered in Task Scheduler. Use 'uninstall' first.\n")
    return 1
  }

  const minutes = Math.max(1, Math.floor(seconds / 60))
  const vbsPath = writeVbsLauncher(scriptPath)
  const trCommand = `wscript.exe /B "${vbsPath}"`

  try {
    execCommand('schtasks', [
      '/create', '/tn', TASK_NAME, '/sc', 'minute', '/mo', String(minutes),
      '/tr', trCommand, '/f',
    ])
  } catch {
    // schtasks failed — remove the launcher file we just wrote to keep state clean
    try { unlinkSync(vbsPath) } catch { /* ignore */ }
    process.stderr.write('Failed to create scheduled task.\n')
    return 1
  }

  process.stdout.write(`Heartbeat registered in Task Scheduler (every ${minutes}m).\n`)
  return 0
}

function uninstallSchtasks(): number {
  try {
    execCommand('schtasks', ['/delete', '/tn', TASK_NAME, '/f'], { allowFailure: true })
  } catch {
    // best effort
  }
  const vbsPath = vbsLauncherPath()
  if (existsSync(vbsPath)) {
    try { unlinkSync(vbsPath) } catch { /* ignore */ }
  }
  process.stdout.write('Heartbeat removed from Task Scheduler.\n')
  return 0
}

export function isSchtasksRegistered(): boolean {
  try {
    execCommand('schtasks', ['/query', '/tn', TASK_NAME])
    return true
  } catch {
    return false
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

export function heartbeatScriptPath(): string {
  // Use process.argv[1] which is the actual script being executed,
  // more reliable than import.meta.url which varies between tsx and bundled output
  const scriptArg = process.argv[1] ?? ''
  if (scriptArg && scriptArg.endsWith('cli.js')) {
    return resolve(scriptArg)
  }
  // Fallback: resolve relative to import.meta.url
  const urlPath = new URL(import.meta.url).pathname.replace(/^\/([a-zA-Z]:)/, '$1')
  return resolve(dirname(urlPath), '..', '..', 'dist', 'cli.js')
}

